// getElementById — selector más rápido para ids
const header = document.getElementById('header');
if (header) {
  console.log(header.textContent); // texto del elemento
} else {
  console.log('No existe ese id');
}

// querySelector — usa sintaxis CSS
const primerBoton = document.querySelector('button');
const botonPrimario = document.querySelector('button.primario');
const inputEmail = document.querySelector('input[type="email"]');

console.log(primerBoton?.textContent); // ?. evita error si es null

// querySelectorAll — selecciona varios
const items = document.querySelectorAll('li');
console.log(items.length); // cuántos hay

// NodeList es iterable con forEach
items.forEach((li, index) => {
  console.log(`Item ${index}: ${li.textContent}`);
});

// Para usar métodos de array (map, filter), convierte:
const textos = Array.from(items).map(li => li.textContent);

