function buscarElemento(lista, selector) {
  if (selector.startsWith('#')) {
    const id = selector.slice(1);
    return lista.find(el => el.id === id) || null;
  }
  if (selector.startsWith('.')) {
    const clase = selector.slice(1);
    return lista.find(el => el.clase === clase) || null;
  }
  return lista.find(el => el.tag === selector) || null;
}

const elementos = [
  { tag: 'h1', id: 'titulo', clase: 'grande' },
  { tag: 'p',  id: 'intro',  clase: 'texto' },
  { tag: 'button', id: 'btn', clase: 'primario' }
];
